args.sparql:
SELECT ?airportLabel ?cityLabel WHERE {
  ?airport wdt:P31 wd:Q1248784 ;
          wdt:P17 wd:Q30 ;
          wdt:P3872 ?traffic .
  ?airport rdfs:label ?airportLabel .
  ?airport wdt:P131 ?city .
  ?city rdfs:label ?cityLabel .
  FILTER(LANG(?airportLabel) = 'en')
  FILTER(LANG(?cityLabel) = 'en')
}
ORDER BY DESC(?traffic)
LIMIT 3

SELECT ?airportLabel ?cityLabel ?traffic WHERE {
  ?airport wdt:P31 wd:Q1248784 .
  ?airport wdt:P17 wd:Q30 .
  ?airport p:P4178 ?statement .
  ?statement ps:P4178 ?traffic .
  OPTIONAL { ?airport wdt:P131 ?city . }
  OPTIONAL { ?city rdfs:label ?cityLabel . FILTER(LANG(?cityLabel) = 'en') }
  ?airport rdfs:label ?airportLabel . FILTER(LANG(?airportLabel) = 'en')
}
ORDER BY DESC(xsd:decimal(?traffic))
LIMIT 1
